// === Source registry ===
// RSS / Reddit feeds. Returns one merged, deduped, time-filtered array.
// 48h lookback (every-2-days cadence). The LLM filter decides relevance per the 7 themes.

const RSS_FEEDS = [
  { url: 'https://techcrunch.com/category/artificial-intelligence/feed/', source: 'techcrunch.com' },
  { url: 'https://www.theverge.com/ai-artificial-intelligence/rss/index.xml', source: 'theverge.com' },
  { url: 'https://www.technologyreview.com/topic/artificial-intelligence/feed', source: 'technologyreview.com' },
  { url: 'https://www.anthropic.com/news/rss.xml', source: 'anthropic.com' },
  { url: 'https://openai.com/blog/rss.xml', source: 'openai.com' },
  { url: 'https://hnrss.org/frontpage?q=AI+OR+LLM+OR+Claude+OR+GPT', source: 'news.ycombinator.com' },
  { url: 'https://www.reddit.com/r/LocalLLaMA/.rss', source: 'reddit.com/r/LocalLLaMA' },
  { url: 'https://www.reddit.com/r/MachineLearning/.rss', source: 'reddit.com/r/MachineLearning' },
  { url: 'https://www.reddit.com/r/singularity/top.rss?t=day', source: 'reddit.com/r/singularity' },
];

const CUTOFF_MS = Date.now() - 48 * 60 * 60 * 1000;

function stripCdata(s = '') {
  return s.replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1').replace(/<[^>]+>/g, '').trim();
}

function parseRss(xml, source) {
  const out = [];
  const blocks = xml.match(/<(item|entry)[\s\S]*?<\/(item|entry)>/g) || [];
  for (const block of blocks) {
    const title = (block.match(/<title[^>]*>([\s\S]*?)<\/title>/) || [, ''])[1];
    const linkMatch =
      block.match(/<link[^>]*href="([^"]+)"/) ||
      block.match(/<link[^>]*>([\s\S]*?)<\/link>/);
    const link = linkMatch ? linkMatch[1] : '';
    const pub =
      (block.match(/<pubDate[^>]*>([\s\S]*?)<\/pubDate>/) || [, ''])[1] ||
      (block.match(/<published[^>]*>([\s\S]*?)<\/published>/) || [, ''])[1] ||
      (block.match(/<updated[^>]*>([\s\S]*?)<\/updated>/) || [, ''])[1];
    const desc =
      (block.match(/<description[^>]*>([\s\S]*?)<\/description>/) || [, ''])[1] ||
      (block.match(/<summary[^>]*>([\s\S]*?)<\/summary>/) || [, ''])[1];
    const publishedMs = pub ? Date.parse(pub) : NaN;
    if (!title || !link) continue;
    out.push({
      title: stripCdata(title),
      url: link.trim(),
      source,
      published_ms: isFinite(publishedMs) ? publishedMs : Date.now(),
      snippet: stripCdata(desc).slice(0, 400),
      kind: 'rss',
    });
  }
  return out;
}

async function fetchFeed({ url, source }) {
  try {
    const xml = await this.helpers.httpRequest({
      method: 'GET',
      url,
      headers: { 'User-Agent': 'Mozilla/5.0 (compatible; LeBrief/1.0; +https://taiyka.com)' },
      returnFullResponse: false,
    });
    return parseRss(typeof xml === 'string' ? xml : String(xml), source);
  } catch (err) {
    console.warn('Feed failed: ' + source + ' ' + err.message);
    return [];
  }
}

const all = [];
for (const feed of RSS_FEEDS) {
  const rows = await fetchFeed.call(this, feed);
  all.push(...rows);
}

const seen = new Set();
const filtered = all
  .filter((i) => i.published_ms >= CUTOFF_MS)
  .filter((i) => { if (seen.has(i.url)) return false; seen.add(i.url); return true; })
  .sort((a, b) => b.published_ms - a.published_ms)
  .slice(0, 120);

return [{ json: { items: filtered, count: filtered.length } }];

// Normalize Apify Twitter rows into our item shape. 48h window.
const CUTOFF_MS = Date.now() - 48 * 60 * 60 * 1000;
const rows = items.map((i) => i.json);
const normalized = rows
  .map((t) => {
    const created = t.createdAt || t.created_at || t.date;
    const ms = created ? Date.parse(created) : Date.now();
    const handle = t.author?.userName || t.user?.screen_name || t.username || 'unknown';
    return {
      title: t.text ? t.text.slice(0, 200) : '',
      url: t.url || t.twitterUrl || ('https://x.com/' + handle + '/status/' + (t.id || '')),
      source: 'x.com/@' + handle,
      published_ms: ms,
      snippet: t.text || '',
      kind: 'tweet',
      engagement: (t.likeCount || 0) + (t.retweetCount || 0) * 2,
    };
  })
  .filter((t) => t.title && t.published_ms >= CUTOFF_MS)
  .sort((a, b) => b.engagement - a.engagement)
  .slice(0, 25);

return [{ json: { items: normalized, count: normalized.length } }];

// Combine both branches into one item list + tag a monotonic issue number.
const combined = [];
for (const i of items) {
  if (Array.isArray(i.json?.items)) combined.push(...i.json.items);
}
const now = new Date();
const start = Date.UTC(now.getUTCFullYear(), 0, 0);
const dayOfYear = Math.floor((now.getTime() - start) / 86400000);
const issueNumber = (now.getUTCFullYear() - 2024) * 365 + dayOfYear;
return [{ json: { items: combined, count: combined.length, issue_number: issueNumber, date_iso: now.toISOString() } }];

