// Build the Resend batch payload — one format-C email per subscriber (own
// unsubscribe token in the footer) + one monitor copy to Manu.
const guard = $('Parse Ollama + Guard').first().json;
const featured = guard.featured;
const quickhits = guard.quickhits;
const issueNumber = guard.issue_number;
const dateLabel = new Date(guard.date_iso).toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' });
const subs = items.map((i) => i.json).filter((s) => s && s.email && s.token);

const SITE = $env.BRIEF_SITE_URL || 'https://taiyka.com';
const FROM = $env.BRIEF_FROM_EMAIL || 'Le Brief <brief@send.taiyka.com>';
const subject = 'Le Brief #' + String(issueNumber).padStart(3, '0') + ' — ' + dateLabel;

function esc(s) { return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'); }

function render(unsubUrl) {
  const featuredRows = featured.map((s, i) => (
    '<tr><td style="padding:0 0 20px 0;">' +
    '<table role="presentation" width="100%"><tr>' +
    '<td width="28" valign="top" style="font-family:ui-monospace,Menlo,monospace;font-size:12px;letter-spacing:0.1em;color:#00a6ff;padding-top:3px;">' + String(i + 1).padStart(2, '0') + '</td>' +
    '<td style="font-family:-apple-system,Segoe UI,Roboto,Arial,sans-serif;">' +
    '<a href="' + s.url + '" style="font-size:16px;font-weight:700;line-height:1.4;color:#e8f0fe;text-decoration:none;">' + esc(s.title) + '</a>' +
    '<div style="font-size:14px;line-height:1.6;color:#b8c6db;margin-top:5px;">' + esc(s.lines) + '</div>' +
    (s.source ? '<div style="margin-top:5px;"><a href="' + s.url + '" style="font-size:11px;color:#00a6ff;text-decoration:none;">' + esc(s.source) + ' &rarr;</a></div>' : '') +
    '</td></tr></table></td></tr>'
  )).join('');

  const quickRows = quickhits.map((s) => (
    '<tr><td style="padding:0 0 11px 0;">' +
    '<table role="presentation" width="100%"><tr>' +
    '<td width="16" valign="top" style="color:#00a6ff;font-size:14px;line-height:1.5;">&bull;</td>' +
    '<td style="font-family:-apple-system,Segoe UI,Roboto,Arial,sans-serif;font-size:13px;line-height:1.5;color:#cdd8ea;">' +
    '<a href="' + s.url + '" style="color:#cdd8ea;text-decoration:none;">' + esc(s.line) + '</a>' +
    (s.source ? ' <span style="font-size:11px;color:#8fa3bd;">&mdash; ' + esc(s.source) + '</span>' : '') +
    '</td></tr></table></td></tr>'
  )).join('');

  const sectionLabel = (txt) => '<tr><td style="padding:4px 0 12px 0;font-family:ui-monospace,Menlo,monospace;font-size:11px;letter-spacing:0.2em;text-transform:uppercase;color:#00a6ff;">' + txt + '</td></tr>';

  const quickBlock = quickhits.length
    ? '<tr><td style="padding:14px 0 0 0;border-top:1px solid rgba(141,162,192,0.18);"><table role="presentation" width="100%">' + sectionLabel('En bref') + quickRows + '</table></td></tr>'
    : '';

  return '<!doctype html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>' +
    '<body style="margin:0;padding:0;background:#0a1628;">' +
    '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#0a1628;"><tr><td align="center" style="padding:28px 16px;">' +
    '<table role="presentation" width="580" cellpadding="0" cellspacing="0" style="max-width:580px;width:100%;background:#0f1a2e;border:1px solid rgba(141,162,192,0.2);border-radius:8px;padding:26px;">' +
    '<tr><td style="border-bottom:1px solid rgba(141,162,192,0.2);padding-bottom:14px;"><table role="presentation" width="100%"><tr>' +
    '<td style="font-family:ui-monospace,Menlo,monospace;font-size:11px;letter-spacing:0.2em;text-transform:uppercase;color:#00a6ff;">LE BRIEF &middot; #' + String(issueNumber).padStart(3, '0') + '</td>' +
    '<td align="right" style="font-family:ui-monospace,Menlo,monospace;font-size:11px;letter-spacing:0.14em;text-transform:uppercase;color:#8fa3bd;">' + dateLabel + '</td>' +
    '</tr></table></td></tr>' +
    '<tr><td style="padding:22px 0 0 0;"><table role="presentation" width="100%">' + sectionLabel('&Agrave; la une') + featuredRows + '</table></td></tr>' +
    quickBlock +
    '<tr><td style="border-top:1px solid rgba(141,162,192,0.2);padding-top:14px;margin-top:6px;text-align:center;font-family:-apple-system,Segoe UI,Roboto,Arial,sans-serif;font-size:12px;color:#8fa3bd;">' +
    '<p style="margin:0 0 6px 0;">&mdash; Manu &middot; <a href="https://instagram.com/manu_ai.to" style="color:#00a6ff;text-decoration:none;">@manu_ai.to</a></p>' +
    '<p style="margin:0;font-size:11px;"><a href="' + unsubUrl + '" style="color:#8fa3bd;text-decoration:underline;">Se d&eacute;sinscrire en 1 clic</a></p>' +
    '</td></tr></table></td></tr></table></body></html>';
}

const batch = [];
// Monitor copy to Manu (visibility for the first ~2 weeks; one email/issue).
batch.push({ from: FROM, to: 'manu.uhila@taiyka.com', subject: '[COPIE] ' + subject, html: render(SITE + '/brief') });
for (const s of subs) {
  const unsub = SITE + '/api/brief/unsubscribe?token=' + s.token;
  batch.push({ from: FROM, to: s.email, subject, html: render(unsub) });
}

return [{ json: { batch, sent_count: subs.length, story_count: (featured.length + quickhits.length) } }];
